from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

client = MongoClient('localhost', 27017)
db = client.cms
profiles_collection = db.user_profiles

@app.route('/profile', methods=['POST'])
def create_profile():
    data = request.json
    profiles_collection.insert_one(data)
    return jsonify({'message': 'Profile created successfully'}), 201

@app.route('/profile/<username>', methods=['GET'])
def get_profile(username):
    profile = profiles_collection.find_one({'username': username})
    if profile:
        profile['_id'] = str(profile['_id'])
        return jsonify(profile)
    return jsonify({'message': 'Profile not found'}), 404

@app.route('/profiles', methods=['GET'])
def get_profiles():
    profiles = list(profiles_collection.find())
    for profile in profiles:
        profile['_id'] = str(profile['_id'])
    return jsonify(profiles)

@app.route('/profile/<username>', methods=['PUT'])
def update_profile(username):
    data = request.json
    result = profiles_collection.update_one({'username': username}, {'$set': data})
    if result.matched_count:
        return jsonify({'message': 'Profile updated successfully'})
    return jsonify({'message': 'Profile not found'}), 404

@app.route('/profile/<username>', methods=['DELETE'])
def delete_profile(username):
    result = profiles_collection.delete_one({'username': username})
    if result.deleted_count:
        return jsonify({'message': 'Profile deleted successfully'})
    return jsonify({'message': 'Profile not found'}), 404

@app.route('/profiles/aggregate', methods=['GET'])
def aggregate_profiles():
    pipeline = [
        {'$group': {'_id': '$role', 'count': {'$sum': 1}}},
        {'$sort': {'count': -1}}
    ]
    result = list(profiles_collection.aggregate(pipeline))
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)